using VisualRelay.Cli;
using VisualRelay.Core.Execution;

namespace VisualRelay.Tests;

/// <summary>
/// Structural-validation suite that exhaustively validates every execution mode
/// in the visual-relay system is properly enumerated, dispatched, and has
/// correct invariants. Pure xUnit [Fact]/[Theory] assertions against the
/// static type surface — no runtime integration needed.
/// </summary>
public sealed class RunAllModesTests
{
    // ── CLI command enumeration ──────────────────────────────────────────

    [Theory]
    [InlineData("launch")]
    [InlineData("run")]
    [InlineData("build")]
    [InlineData("test")]
    [InlineData("format")]
    [InlineData("screenshot")]
    [InlineData("run-task")]
    [InlineData("init")]
    [InlineData("check")]
    [InlineData("inspect")]
    [InlineData("gen-backend-config")]
    [InlineData("guards")]
    [InlineData("install-hooks")]
    [InlineData("bump-version")]
    [InlineData("provision-mxc")]
    public void AllCliCommands_AreRecognizedByRouter(string cmd)
    {
        Assert.True(CommandRouter.IsKnown(cmd),
            $"'{cmd}' should be a known subcommand");
    }

    [Fact]
    public void KnownCommands_CountIsFifteen()
    {
        // Every subcommand in the KnownCommands list must be recognized.
        // There are exactly 15 entries (including the "run" alias).
        var expected = new[]
        {
            "launch", "run", "build", "test", "format", "screenshot",
            "run-task", "init", "check", "inspect", "gen-backend-config",
            "guards", "install-hooks", "bump-version", "provision-mxc",
        };

        foreach (var cmd in expected)
            Assert.True(CommandRouter.IsKnown(cmd),
                $"'{cmd}' must be known for the count assertion to hold");

        // Any command NOT in the list must be rejected.
        Assert.False(CommandRouter.IsKnown("nonexistent-command"));
    }

    [Fact]
    public void UsageLine_ContainsEverySubcommand()
    {
        var usage = CommandRouter.UsageLine;

        // Every known subcommand (except the "run" alias) must appear in the
        // usage line so users can discover it.
        var mustAppear = new[]
        {
            "launch", "build", "test", "format", "screenshot", "run-task",
            "init", "install-hooks", "bump-version", "check", "inspect",
            "guards", "gen-backend-config", "provision-mxc",
        };

        foreach (var cmd in mustAppear)
            Assert.Contains(cmd, usage, StringComparison.Ordinal);

        // "run" is an alias of "launch" and may not appear separately.
    }

    // ── Guard subcommand enumeration ─────────────────────────────────────

    [Fact]
    public void AllGuardSubcommands_AreDispatched()
    {
        var paths = RepoPaths.Resolve();
        var guardsProgram = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Guards", "Program.cs"));

        // The switch expression must contain case arms for all 4 guard
        // subcommands plus a default/underscore fallback.
        Assert.Contains("\"shell-size\"", guardsProgram, StringComparison.Ordinal);
        Assert.Contains("\"file-size\"", guardsProgram, StringComparison.Ordinal);
        Assert.Contains("\"source-enumeration\"", guardsProgram, StringComparison.Ordinal);
        Assert.Contains("\"sync-over-async\"", guardsProgram, StringComparison.Ordinal);
        Assert.Contains("_ =>", guardsProgram, StringComparison.Ordinal);
    }

    [Fact]
    public void GuardSubcommand_DefaultIsShellSize()
    {
        var paths = RepoPaths.Resolve();
        var guardsProgram = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Guards", "Program.cs"));

        // When no subcommand is given, the guards tool defaults to shell-size.
        Assert.Contains("\"shell-size\"", guardsProgram, StringComparison.Ordinal);
    }

    // ── Relay stage enumeration ──────────────────────────────────────────

    [Theory]
    [InlineData(1, "Ideate", "cheap", "none")]
    [InlineData(2, "Research", "cheap", "some")]
    [InlineData(3, "Diagnose", "balanced", "some")]
    [InlineData(4, "Plan", "balanced", "some")]
    [InlineData(5, "Author-tests", "balanced", "all")]
    [InlineData(6, "Implement", "balanced", "all")]
    [InlineData(7, "Review", "frontier", "some")]
    [InlineData(8, "Fix", "balanced", "all")]
    [InlineData(9, "Verify", "cheap", "some")]
    [InlineData(10, "Fix-verify", "balanced", "all")]
    [InlineData(11, "Commit", "cheap", "driver")]
    public void AllRelayStages_HaveCorrectMetadata(
        int number, string name, string tier, string files)
    {
        var stage = RelayStages.All.Single(s => s.Number == number);

        Assert.Equal(name, stage.Name);
        Assert.Equal(tier, stage.Tier);
        Assert.Equal(files, stage.Files);
        Assert.NotNull(stage.SystemPrompt);
        Assert.NotEmpty(stage.SystemPrompt);
        Assert.NotNull(stage.OutputContract);
    }

    [Fact]
    public void Stages_CountIsEleven()
    {
        Assert.Equal(11, RelayStages.All.Count);
    }

    // ── Check gate step enumeration ──────────────────────────────────────

    [Fact]
    public void CheckGate_HasAllRequiredSteps()
    {
        var paths = RepoPaths.Resolve();
        var checkSource = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Cli", "Commands",
                "CheckCommand.cs"));

        // The 9 steps must appear in order in the RunAsync method body:
        // 1. Source-enumeration guard
        Assert.Contains("SourceEnumerationAsync", checkSource, StringComparison.Ordinal);
        // 2. File-size guard
        Assert.Contains("FileSize", checkSource, StringComparison.Ordinal);
        // 3. Shell-size guard
        Assert.Contains("ShellSizeAsync", checkSource, StringComparison.Ordinal);
        // 4. Dead-config-field guard
        Assert.Contains("DeadConfigFields", checkSource, StringComparison.Ordinal);
        // 5. dotnet format --verify-no-changes
        Assert.Contains("--verify-no-changes", checkSource, StringComparison.Ordinal);
        // 6. Build
        Assert.Contains("\"build\"", checkSource, StringComparison.Ordinal);
        // 7. InspectCode
        Assert.Contains("InspectCodeGate", checkSource, StringComparison.Ordinal);
        // 8. Watchdog'd tests
        Assert.Contains("RunWatchedTestsAsync", checkSource, StringComparison.Ordinal);
        // 9. Screenshots
        Assert.Contains("BuildAndRenderScreenshots", checkSource, StringComparison.Ordinal);
    }

    // ── Backend lifecycle command enumeration ────────────────────────────

    [Fact]
    public void BackendLifecycle_HasAllCommands()
    {
        var paths = RepoPaths.Resolve();
        var backendProgram = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Backend", "Program.cs"));

        // The switch must dispatch start, stop, and status.
        Assert.Contains("\"start\"", backendProgram, StringComparison.Ordinal);
        Assert.Contains("\"stop\"", backendProgram, StringComparison.Ordinal);
        Assert.Contains("\"status\"", backendProgram, StringComparison.Ordinal);
        // Must have a default/usage fallback.
        Assert.Contains("default:", backendProgram, StringComparison.Ordinal);
    }

    // ── Nix flake architecture enumeration ───────────────────────────────

    [Fact]
    public void NixFlake_HasAllArchitectures()
    {
        var paths = RepoPaths.Resolve();
        var flakeNix = File.ReadAllText(Path.Combine(paths.Root, "flake.nix"));

        Assert.Contains("aarch64-darwin", flakeNix, StringComparison.Ordinal);
        Assert.Contains("x86_64-darwin", flakeNix, StringComparison.Ordinal);
        Assert.Contains("x86_64-linux", flakeNix, StringComparison.Ordinal);
        Assert.Contains("aarch64-linux", flakeNix, StringComparison.Ordinal);
    }

    // ── CI matrix RID enumeration ────────────────────────────────────────

    [Fact]
    public void CiMatrix_HasAllReleaseRids()
    {
        var paths = RepoPaths.Resolve();
        var releaseYml = File.ReadAllText(
            Path.Combine(paths.Root, ".github", "workflows", "release.yml"));

        Assert.Contains("osx-arm64", releaseYml, StringComparison.Ordinal);
        Assert.Contains("osx-x64", releaseYml, StringComparison.Ordinal);
        Assert.Contains("win-x64", releaseYml, StringComparison.Ordinal);
    }

    // ── Passthrough command enumeration ──────────────────────────────────

    [Fact]
    public void PassthroughCommand_DispatchesAllThreeTools()
    {
        var paths = RepoPaths.Resolve();
        var passthroughSource = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Cli", "Commands",
                "PassthroughCommand.cs"));

        // The three passthrough tools must each have a named method.
        Assert.Contains("RunTask", passthroughSource, StringComparison.Ordinal);
        Assert.Contains("GenBackendConfig", passthroughSource, StringComparison.Ordinal);
        Assert.Contains("Guards", passthroughSource, StringComparison.Ordinal);
    }
}

using VisualRelay.Cli;
using VisualRelay.Core.Execution;

namespace VisualRelay.Tests;

/// <summary>
/// Validates that every known command, guard subcommand, and backend command
/// is properly dispatched by its respective Program.cs switch expression.
/// Parses source text to assert case-arm coverage — no runtime integration.
/// </summary>
public sealed class RunAllModesCommandDispatchTests
{
    // ── CLI Program.cs dispatch coverage ─────────────────────────────────

    [Fact]
    public void CliProgramDispatch_CoversAllKnownCommands()
    {
        var paths = RepoPaths.Resolve();
        var cliProgram = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Cli", "Program.cs"));

        // Every known subcommand must have a case arm in the switch expression.
        var knownCommands = new[]
        {
            "launch", "run", "build", "test", "format", "screenshot",
            "run-task", "init", "check", "inspect", "gen-backend-config",
            "guards", "install-hooks", "bump-version", "provision-mxc",
        };

        foreach (var cmd in knownCommands)
        {
            Assert.True(CommandRouter.IsKnown(cmd),
                $"'{cmd}' must be a known command for dispatch coverage");

            // Each command must appear as a string literal in the switch.
            Assert.Contains($"\"{cmd}\"", cliProgram, StringComparison.Ordinal);
        }

        // The switch must have a default/underscore fallback.
        Assert.Contains("_ =>", cliProgram, StringComparison.Ordinal);
    }

    // ── Guards Program.cs dispatch coverage ──────────────────────────────

    [Fact]
    public void GuardProgramDispatch_CoversAllSubcommands()
    {
        var paths = RepoPaths.Resolve();
        var guardsProgram = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Guards", "Program.cs"));

        var guardSubcommands = new[]
        {
            "shell-size", "file-size", "source-enumeration", "sync-over-async",
        };

        foreach (var sub in guardSubcommands)
            Assert.Contains($"\"{sub}\"", guardsProgram, StringComparison.Ordinal);

        // Must have a default/underscore fallback.
        Assert.Contains("_ =>", guardsProgram, StringComparison.Ordinal);
    }

    // ── Backend Program.cs dispatch coverage ─────────────────────────────

    [Fact]
    public void BackendProgramDispatch_CoversAllCommands()
    {
        var paths = RepoPaths.Resolve();
        var backendProgram = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Backend", "Program.cs"));

        var backendCommands = new[] { "start", "stop", "status" };

        foreach (var cmd in backendCommands)
            Assert.Contains($"\"{cmd}\"", backendProgram, StringComparison.Ordinal);

        // Must have a default usage fallback.
        Assert.Contains("default:", backendProgram, StringComparison.Ordinal);
    }

    // ── Passthrough command method coverage ──────────────────────────────

    [Fact]
    public void PassthroughCommand_DispatchesRunTask_GenBackendConfig_Guards()
    {
        var paths = RepoPaths.Resolve();
        var passthroughSource = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Cli", "Commands",
                "PassthroughCommand.cs"));

        // Each passthrough must have a method that forwards to the tool project.
        Assert.Contains("RunTask", passthroughSource, StringComparison.Ordinal);
        Assert.Contains("GenBackendConfig", passthroughSource, StringComparison.Ordinal);
        Assert.Contains("Guards", passthroughSource, StringComparison.Ordinal);

        // The forwarding helper must reference each tool project name.
        Assert.Contains("VisualRelay.RunTask", passthroughSource, StringComparison.Ordinal);
        Assert.Contains("VisualRelay.GenBackendConfig", passthroughSource, StringComparison.Ordinal);
        Assert.Contains("VisualRelay.Guards", passthroughSource, StringComparison.Ordinal);
    }

    // ── CLI switch expression has launch/run alias ───────────────────────

    [Fact]
    public void CliProgramDispatch_LaunchAndRun_ShareSameArm()
    {
        var paths = RepoPaths.Resolve();
        var cliProgram = File.ReadAllText(
            Path.Combine(paths.Root, "tools", "VisualRelay.Cli", "Program.cs"));

        // "launch" and "run" must share the same switch arm (or pattern).
        Assert.Contains("\"launch\" or \"run\"", cliProgram, StringComparison.Ordinal);
    }
}

using VisualRelay.Core.Execution;

namespace VisualRelay.Tests;

/// <summary>
/// Exhaustive contract validation for every relay stage definition:
/// system prompts, output contracts, tier and files-scope invariants,
/// sequential numbering, and kind/scope exclusivity.
/// </summary>
public sealed class RunAllModesStageContractsTests
{
    // ── System prompt invariants ─────────────────────────────────────────

    [Theory]
    [InlineData(1)]
    [InlineData(2)]
    [InlineData(3)]
    [InlineData(4)]
    [InlineData(5)]
    [InlineData(6)]
    [InlineData(7)]
    [InlineData(8)]
    [InlineData(9)]
    [InlineData(10)]
    public void AllStages_HaveNonEmptySystemPrompt(int number)
    {
        var stage = RelayStages.All.Single(s => s.Number == number);
        Assert.False(string.IsNullOrWhiteSpace(stage.SystemPrompt),
            $"Stage {number} ({stage.Name}) must have a non-empty SystemPrompt");
    }

    [Fact]
    public void CommitStage_HasEmptySystemPrompt()
    {
        var commit = RelayStages.All.Single(s => s.Number == 11);
        // Stage 11 (Commit) is a driver stage with no LLM — its prompt is empty.
        Assert.Equal(string.Empty, commit.SystemPrompt);
    }

    // ── Output contract invariants ───────────────────────────────────────

    [Theory]
    [InlineData(1)]
    [InlineData(2)]
    [InlineData(3)]
    [InlineData(4)]
    [InlineData(5)]
    [InlineData(6)]
    [InlineData(7)]
    [InlineData(8)]
    [InlineData(9)]
    [InlineData(10)]
    public void AllLlmStages_HaveNonEmptyOutputContract(int number)
    {
        var stage = RelayStages.All.Single(s => s.Number == number);
        Assert.False(string.IsNullOrWhiteSpace(stage.OutputContract),
            $"Stage {number} ({stage.Name}) must have a non-empty OutputContract");
    }

    [Fact]
    public void CommitStage_HasEmptyOutputContract()
    {
        var commit = RelayStages.All.Single(s => s.Number == 11);
        // Stage 11 (Commit) is a driver stage — no LLM output contract.
        Assert.Equal(string.Empty, commit.OutputContract);
    }

    // ── Tier invariants ──────────────────────────────────────────────────

    private static readonly HashSet<string> ValidTiers =
        new(StringComparer.Ordinal) { "cheap", "balanced", "frontier" };

    [Theory]
    [InlineData(1)]
    [InlineData(2)]
    [InlineData(3)]
    [InlineData(4)]
    [InlineData(5)]
    [InlineData(6)]
    [InlineData(7)]
    [InlineData(8)]
    [InlineData(9)]
    [InlineData(10)]
    [InlineData(11)]
    public void AllStages_HaveValidTier(int number)
    {
        var stage = RelayStages.All.Single(s => s.Number == number);
        Assert.True(ValidTiers.Contains(stage.Tier),
            $"Stage {number} ({stage.Name}) has invalid tier '{stage.Tier}'. " +
            $"Must be one of: cheap, balanced, frontier.");
    }

    // ── Files-scope invariants ───────────────────────────────────────────

    private static readonly HashSet<string> ValidFilesScopes =
        new(StringComparer.Ordinal) { "none", "some", "all", "driver" };

    [Theory]
    [InlineData(1)]
    [InlineData(2)]
    [InlineData(3)]
    [InlineData(4)]
    [InlineData(5)]
    [InlineData(6)]
    [InlineData(7)]
    [InlineData(8)]
    [InlineData(9)]
    [InlineData(10)]
    [InlineData(11)]
    public void AllStages_HaveValidFilesScope(int number)
    {
        var stage = RelayStages.All.Single(s => s.Number == number);
        Assert.True(ValidFilesScopes.Contains(stage.Files),
            $"Stage {number} ({stage.Name}) has invalid Files scope '{stage.Files}'. " +
            "Must be one of: none, some, all, driver.");
    }

    // ── Commands invariants ──────────────────────────────────────────────

    [Theory]
    [InlineData(1)]
    [InlineData(2)]
    [InlineData(3)]
    [InlineData(4)]
    [InlineData(5)]
    [InlineData(6)]
    [InlineData(7)]
    [InlineData(8)]
    [InlineData(9)]
    [InlineData(10)]
    [InlineData(11)]
    public void AllStages_HaveNonEmptyCommands(int number)
    {
        var stage = RelayStages.All.Single(s => s.Number == number);
        Assert.False(string.IsNullOrWhiteSpace(stage.Commands),
            $"Stage {number} ({stage.Name}) must have a non-empty Commands string");
    }

    // ── Sequential numbering ─────────────────────────────────────────────

    [Fact]
    public void Stages_AreSequential_OneThroughEleven()
    {
        var numbers = RelayStages.All.Select(s => s.Number).OrderBy(n => n).ToList();

        Assert.Equal(11, numbers.Count);
        for (var i = 0; i < 11; i++)
            Assert.Equal(i + 1, numbers[i]);
    }

    [Fact]
    public void Stages_HaveNoDuplicateNumbers()
    {
        var numbers = RelayStages.All.Select(s => s.Number).ToList();
        Assert.Equal(numbers.Distinct().Count(), numbers.Count);
    }

    // ── Kind exclusivity ─────────────────────────────────────────────────

    [Fact]
    public void OnlyCommitStage_HasDriverKind()
    {
        foreach (var stage in RelayStages.All)
        {
            if (stage.Number == 11)
                Assert.Equal("driver", stage.Kind);
            else
                Assert.Equal("llm", stage.Kind);
        }
    }

    // ── Files-scope exclusivity ──────────────────────────────────────────

    [Fact]
    public void OnlyIdeateStage_HasNoneFilesScope()
    {
        foreach (var stage in RelayStages.All)
        {
            if (stage.Number == 1)
                Assert.Equal("none", stage.Files);
            else
                Assert.NotEqual("none", stage.Files);
        }
    }

    // ── Name uniqueness ──────────────────────────────────────────────────

    [Fact]
    public void Stages_HaveUniqueNames()
    {
        var names = RelayStages.All.Select(s => s.Name).ToList();
        Assert.Equal(names.Distinct().Count(), names.Count);
    }

    // ── System prompt contains stage-specific keywords ──────────────────

    [Theory]
    [InlineData(1, "Ideate", "options")]
    [InlineData(2, "Research", "findings")]
    [InlineData(3, "Diagnose", "evidence")]
    [InlineData(4, "Plan", "manifest")]
    [InlineData(5, "Author-tests", "tests")]
    [InlineData(6, "Implement", "Implement the change")]
    [InlineData(7, "Review", "Review")]
    [InlineData(8, "Fix", "Resolve every blocker")]
    [InlineData(9, "Verify", "Summarize")]
    [InlineData(10, "Fix-verify", "Fix all failures")]
    public void StageSystemPrompt_ContainsExpectedKeywords(
        int number, string name, string keyword)
    {
        var stage = RelayStages.All.Single(s => s.Number == number);
        Assert.Equal(name, stage.Name);
        Assert.Contains(keyword, stage.SystemPrompt, StringComparison.OrdinalIgnoreCase);
    }

    // ── Output contract JSON structure ───────────────────────────────────

    [Fact]
    public void AllLlmStageContracts_ReferenceFencedJsonBlock()
    {
        foreach (var stage in RelayStages.All.Where(s => s.Kind == "llm"))
        {
            Assert.Contains("```json", stage.OutputContract, StringComparison.Ordinal);
            Assert.Contains("block", stage.OutputContract, StringComparison.OrdinalIgnoreCase);
        }
    }
}

